type GeoCoord = [number, number];
type GeoLine = GeoCoord[];
type LandDot = [number, number, number];
type Vec3 = {x: number; y: number; z: number};
type ViewVec = Vec3;
type ViewState = {
  cosLon: number;
  sinLon: number;
  cosLat: number;
  sinLat: number;
};

type Hub = {
  id: string;
  lon: number;
  lat: number;
  tier: 1 | 2 | 3;
};

type RouteRisk = 'critical' | 'warning';
type Route = {
  from: string;
  to: string;
  risk?: RouteRisk;
  height?: number;
};

type HubVector = Hub & {vector: Vec3};
type RouteGeometry = Route & {
  index: number;
  start: Vec3;
  end: Vec3;
  omega: number;
  sinOmega: number;
  heightValue: number;
};

type CloudDataCenter = {
  hubId: string;
  region: string;
  capacity: number;
};

type DdosCluster = {
  id: string;
  target: string;
  angle: number;
  orbit: number;
  period: 180 | 225 | 300;
  offset: number;
  color: 'critical' | 'warning';
  curve: number;
};

type RoutePoint = {
  x: number;
  y: number;
  z: number;
  visible: boolean;
  t: number;
};

