const buildVisibleLinePath = (lines: Vec3[][], view: ViewState) => {
  let path = '';
  for (const line of lines) {
    if (line.length < 2) continue;
    let previous = rotateToView(line[0], view);
    let previousVisible = previous.z >= 0;
    let drawing = false;
    const allVisible = line.every((point) => rotateToView(point, view).z >= 0);
    if (previousVisible) {
      const screen = toScreen(previous);
      path += `M${screen.x} ${screen.y}`;
      drawing = true;
    }
    for (let index = 1; index < line.length; index++) {
      const current = rotateToView(line[index], view);
      const currentVisible = current.z >= 0;
      if (previousVisible && currentVisible) {
        if (!drawing) {
          const start = toScreen(previous);
          path += `M${start.x} ${start.y}`;
        }
        const screen = toScreen(current);
        path += `L${screen.x} ${screen.y}`;
        drawing = true;
      } else if (previousVisible && !currentVisible) {
        const screen = toScreen(horizonIntersection(previous, current));
        path += `L${screen.x} ${screen.y}`;
        drawing = false;
      } else if (!previousVisible && currentVisible) {
        const boundary = toScreen(horizonIntersection(previous, current));
        const screen = toScreen(current);
        path += `M${boundary.x} ${boundary.y}L${screen.x} ${screen.y}`;
        drawing = true;
      }
      previous = current;
      previousVisible = currentVisible;
    }
    const first = line[0];
    const last = line[line.length - 1];
    const closed = Math.hypot(first.x - last.x, first.y - last.y, first.z - last.z) < 0.0001;
    if (closed && allVisible) path += 'Z';
  }
  return path;
};

const buildLandDotPaths = (view: ViewState) => {
  const buckets = ['', '', '', ''];
  for (const dot of LAND_DOT_VECTORS) {
    const point = rotateToView(dot.vector, view);
    if (point.z <= 0.01) continue;
    const screen = toScreen(point);
    const radius = round1(dot.size * (0.38 + point.z * 0.68));
    const bucket = Math.min(3, Math.floor(point.z * 4));
    buckets[bucket] += `M${round1(screen.x - radius)} ${screen.y}a${radius} ${radius} 0 1 0 ${round1(
      radius * 2,
    )} 0a${radius} ${radius} 0 1 0 ${round1(-radius * 2)} 0`;
  }
  return buckets;
};

const evaluateRoutePoint = (route: RouteGeometry, t: number, view: ViewState): RoutePoint => {
  const unit = slerpVector(route.start, route.end, route.omega, route.sinOmega, t);
  const lift = 1 + route.heightValue * Math.pow(Math.max(0, Math.sin(Math.PI * t)), 1.25);
  const rotated = rotateToView(unit, view);
  const qx = rotated.x * lift;
  const qy = rotated.y * lift;
  const qz = rotated.z * lift;
  const radialSquared = qx * qx + qy * qy;
  const visible =
    radialSquared >= 1 || qz >= Math.sqrt(Math.max(0, 1 - radialSquared)) - 0.0015;
  return {
    x: round1(GLOBE_CX + GLOBE_RADIUS * qx),
    y: round1(GLOBE_CY - GLOBE_RADIUS * qy),
    z: qz,
    visible,
    t,
  };
};

const findRouteBoundary = (
  route: RouteGeometry,
  view: ViewState,
  start: RoutePoint,
  end: RoutePoint,
) => {
  let low = start.t;
  let high = end.t;
  const startVisibility = start.visible;
  for (let iteration = 0; iteration < 7; iteration++) {
    const middle = (low + high) / 2;
    const point = evaluateRoutePoint(route, middle, view);
    if (point.visible === startVisibility) low = middle;
    else high = middle;
  }
  return evaluateRoutePoint(route, startVisibility ? low : high, view);
};

const buildRoutePath = (route: RouteGeometry, view: ViewState) => {
  const samples = 40;
  let path = '';
  let previous = evaluateRoutePoint(route, 0, view);
  let drawing = false;
  if (previous.visible) {
    path += `M${previous.x} ${previous.y}`;
    drawing = true;
  }
  for (let index = 1; index <= samples; index++) {
    const current = evaluateRoutePoint(route, index / samples, view);
    if (previous.visible && current.visible) {
      if (!drawing) path += `M${previous.x} ${previous.y}`;
      path += `L${current.x} ${current.y}`;
      drawing = true;
    } else if (previous.visible && !current.visible) {
      const boundary = findRouteBoundary(route, view, previous, current);
      path += `L${boundary.x} ${boundary.y}`;
      drawing = false;
    } else if (!previous.visible && current.visible) {
      const boundary = findRouteBoundary(route, view, previous, current);
      path += `M${boundary.x} ${boundary.y}L${current.x} ${current.y}`;
      drawing = true;
    }
    previous = current;
  }
  return path;
};

